arguments.new_str:
// EF Core 9 breaking change: Migrate() now manages its own transactions
// internally via the migration history table. Wrapping it in an explicit
// user transaction is no longer allowed and throws InvalidOperationException.
void ApplyMigrations(AppDbContext db)
{
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        db.Database.Migrate();
    });
}

